def format_structured_message(content):
    if isinstance(content, dict):
        return json.dumps({
            'default': json.dumps(content),
            'email': json.dumps(content, indent=2),
            'sqs': json.dumps(content)
        })
    else:
        return content


def format_default_message(content):
    if isinstance(content, dict):
        return json.dumps(content)
    else:
        return str(content)


def build_message_attributes(attributes, notification_type):
    sns_attributes = {
        'notification_type': {
            'DataType': 'String',
            'StringValue': notification_type
        },
        'timestamp': {
            'DataType': 'String',
            'StringValue': datetime.utcnow().isoformat()
        }
    }
    
    for key, value in attributes.items():
        if isinstance(value, (int, float)):
            sns_attributes[key] = {
                'DataType': 'Number',
                'StringValue': str(value)
            }
        elif isinstance(value, str):
            sns_attributes[key] = {
                'DataType': 'String',
                'StringValue': value
            }
        elif isinstance(value, list):
            sns_attributes[key] = {
                'DataType': 'String.Array',
                'StringValue': json.dumps(value)
            }
    
    return sns_attributes


def publish_to_sns(topic_arn, message, subject, message_attributes):
    try:
        if message.startswith('{') and '"default"' in message:
            response = sns_client.publish(
                TopicArn=topic_arn,
                Message=message,
                Subject=subject,
                MessageAttributes=message_attributes,
                MessageStructure='json'
            )
        else:
            response = sns_client.publish(
                TopicArn=topic_arn,
                Message=message,
                Subject=subject,
                MessageAttributes=message_attributes
            )
        
        return response
        
    except Exception as e:
        print(f"Error publishing to SNS: {str(e)}")
        raise